311	#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_TILING)
312	    const uint32_t col = ker_dim_y * ker_dim_x * in_tensor_ch;
313	    const uint32_t tiling_size = 256;
314	    long maxvl_per_loop;
315	
316	    //--- calculate the buffer address ---
317	    const long align_byte = 64;
318	    // buf_A
319	    int8_t *src1 = (int8_t*)in_tmp_buf;
320	    src1 = (int8_t*)nn_align((unsigned long)src1, align_byte);                  // align the starting addresss
321	    // buf_B: converted src2
322	    long src1_size = tiling_size * in_tensor_ch * ker_dim_x * ker_dim_y;
323	    int8_t *src2 = (int8_t*)(src1 + src1_size);
324	    src2 = (int8_t*)nn_align((unsigned long)src2, align_byte);                  // align the starting addresss
325	    // buf_C: temp buffer for int32_t tiling accumulator
326	    long src2_size = out_tensor_ch * in_tensor_ch * ker_dim_x * ker_dim_y;
327	    int32_t *dst_i32 = (int32_t*)(src2 + src2_size);
328	    dst_i32 = (int32_t*)nn_align((unsigned long)dst_i32, align_byte);           // align the starting addresss
329	    // buf_contri
330	    long dst_i32_size = tiling_size * out_tensor_ch;
331	    int32_t *contri_buf = (int32_t*)(dst_i32 + dst_i32_size);
332	    contri_buf = (int32_t*)nn_align((unsigned long)contri_buf, align_byte);     // align the starting addresss
333	
334	    // calculate the weight contribution
335	    const int8_t *pWt = ker_weight;
336	    int32_t *pContri_buf = contri_buf;
337	    const int32_t *pBias = bias;
338	    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
339	    if (bias != NULL)
340	    {
341	        long out_tensor_ch2 = out_tensor_ch;
342	        long vl;
343	        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
344	        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum
345	
346	        while (out_tensor_ch2 > 0)
347	        {
348	            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
349	            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
350	            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
351	            NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);     // const one for vd4dot
352	
353	            long rhs_cols2 = col;
354	            while (rhs_cols2 >= maxvl_per_loop)
355	            {
356	                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
357	                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
358	                pWt += vl;
359	                rhs_cols2 -= vl;
360	
361	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
362	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
363	            }
364	
365	            //clean one of the dot product source
366	            long tmp_avl;
367	            tmp_avl = rhs_cols2 + 3;
368	            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
369	            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
370	            NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
371	            NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot
372	
373	            // remain loop
374	            while (rhs_cols2 > 0)
375	            {
376	                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
377	                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
378	                pWt += vl;
379	                rhs_cols2 -= vl;
380	
381	                vl = (vl + 3) >> 2;
382	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
383	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
384	            }
385	
386	            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
387	            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
388	
389	            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
390	            NDS_VEC_VLE32_V(NDS_VEC_V1, pBias);
391	            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution
392	            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V1);    // add bias
393	            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
394	            pBias += vl;
395	            pContri_buf += vl;
396	            out_tensor_ch2--;
397	        }
398	    }
399	    else
400	    {
401	        long out_tensor_ch2 = out_tensor_ch;
402	        long vl;
403	        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
404	        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum
405	
406	        while (out_tensor_ch2 > 0)
407	        {
408	            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
409	            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
410	            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
411	            NDS_VEC_VMV_V_I(NDS_VEC_V8, 1);     // const one for vd4dot
412	
413	            long rhs_cols2 = col;
414	            while (rhs_cols2 >= maxvl_per_loop)
415	            {
416	                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
417	                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
418	                pWt += vl;
419	                rhs_cols2 -= vl;
420	
421	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
422	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
423	            }
424	
425	            //clean one of the dot product source
426	            long tmp_avl;
427	            tmp_avl = rhs_cols2 + 3;
428	            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
429	            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
430	            NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
431	            NDS_VEC_VADD_VI(NDS_VEC_V8, NDS_VEC_V8, 1);     // const one for vd4dot
432	
433	            // remain loop
434	            while (rhs_cols2 > 0)
435	            {
436	                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
437	                NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
438	                pWt += vl;
439	                rhs_cols2 -= vl;
440	
441	                vl = (vl + 3) >> 2;
442	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
443	                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V8);
444	            }
445	
446	            NDS_VEC_VSETVLI(vl, col, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);   //note the avl here
447	            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
448	
449	            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
450	            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);
451	            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
452	            pContri_buf++;
453	            out_tensor_ch2--;
454	        }
455	    }
456	
457	    /* When out_tensor_ch is small, the tiling GEMM (vqmacc vectorizing across
458	     * out_tensor_ch) severely underutilizes vector width.  Switch to vd4dots
459	     * which vectorizes along the reduction dimension (col) instead — giving
460	     * up to 32x better vector utilization for small channel counts.
461	     * Uses 4-column batching with nn_mat_mult_kernel_s8_offset_unroll4 (4x4
462	     * tiled GEMM, LMUL=M1) for ~2x throughput vs the old 2-column v4 path.
463	     *
464	     * im2col is split into top/mid/bottom regions: the mid region (no padding)
465	     * uses bulk row copies (ker_dim_x * in_tensor_ch per kernel row) instead
466	     * of per-position copies, reducing vector load/store pairs by ~3x. */
467	    if (out_tensor_ch <= 64)
468	    {
469	        /* Reuse src1 area as the 8-column im2col buffer (tiling buffer is
470	         * much larger than what 8-column batching needs). Double-pump:
471	         * im2col 8 pixels, then call unroll4 twice (pix 0-3, pix 4-7).
472	         * Weights stay in L1 cache between the two calls. */
473	        int8_t *eight_column_buf = src1;
474	        const int8_t pad_val = (int8_t)(-in_offset);
475	
476	        /* Precompute non-padded output region boundaries (clamped to output dims) */
477	        long bound_y_begin = (pad_y + stride_y - 1) / stride_y;
478	        long bound_y_end   = (in_tensor_dim_y + pad_y - ker_dim_y + stride_y) / stride_y;
479	        long bound_x_begin = (pad_x + stride_x - 1) / stride_x;
480	        long bound_x_end   = (in_tensor_dim_x + pad_x - ker_dim_x + stride_x) / stride_x;
481	        if (bound_y_begin > out_tensor_dim_y) bound_y_begin = out_tensor_dim_y;
482	        if (bound_y_end > out_tensor_dim_y)   bound_y_end = out_tensor_dim_y;
483	        if (bound_x_begin > out_tensor_dim_x) bound_x_begin = out_tensor_dim_x;
484	        if (bound_x_end > out_tensor_dim_x)   bound_x_end = out_tensor_dim_x;
485	
486	        /* Macro to flush the im2col buffer when 8 columns are ready.
487	         * Calls unroll4 kernel twice: first for pixels 0-3, then pixels 4-7.
488	         * Weight data (ker_weight) is the same for both calls → L1 cache reuse. */
489	#define FLUSH_IM2COL_UNROLL8()                                                  \
490	        if (col_ptr == eight_column_buf + 8 * col)                              \
491	        {                                                                       \
492	            out = nn_mat_mult_kernel_s8_offset_unroll4(ker_weight,              \
493	                                                  eight_column_buf,             \
494	                                                  out_tensor_ch,                \
495	                                                  out_shift,                    \
496	                                                  out_scale,                    \
497	                                                  in_offset,                    \
498	                                                  out_offset,                   \
499	                                                  act_min,                      \
500	                                                  act_max,                      \
501	                                                  col,                          \
502	                                                  contri_buf,                   \
503	                                                  out);                         \
504	            out = nn_mat_mult_kernel_s8_offset_unroll4(ker_weight,              \
505	                                                  eight_column_buf + 4 * col,   \
506	                                                  out_tensor_ch,                \
507	                                                  out_shift,                    \
508	                                                  out_scale,                    \
509	                                                  in_offset,                    \
510	                                                  out_offset,                   \
511	                                                  act_min,                      \
512	                                                  act_max,                      \
513	                                                  col,                          \
514	                                                  contri_buf,                   \
515	                                                  out);                         \
516	            col_ptr = eight_column_buf;                                         \
517	        }
518	
519	        for (long cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
520	        {
521	            int8_t *col_ptr = eight_column_buf;
522	            int8_t *out = out_tensor;
523	            long cur_out_y, cur_out_x, cur_ker_y, cur_ker_x;
524	
525	            /* === Top region: output rows that need y-padding === */
526	            for (cur_out_y = 0; cur_out_y < bound_y_begin; cur_out_y++)
527	            {
528	                for (cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
529	                {
530	                    const long ker_y_start = cur_out_y * stride_y - pad_y;
531	                    const long ker_x_start = cur_out_x * stride_x - pad_x;
532	                    for (cur_ker_y = ker_y_start; cur_ker_y < ker_y_start + ker_dim_y; cur_ker_y++)
533	                    {
534	                        for (cur_ker_x = ker_x_start; cur_ker_x < ker_x_start + ker_dim_x; cur_ker_x++)
535	                        {
536	                            if (cur_ker_y < 0 || cur_ker_y >= in_tensor_dim_y || cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
537	                            {
538	                                nn_set_val_s8(col_ptr, pad_val, in_tensor_ch);
539	                            }
540	                            else
541	                            {
542	                                nn_dup_s8_m1(in_tensor + (cur_ker_y * in_tensor_dim_x + cur_ker_x) * in_tensor_ch, col_ptr, in_tensor_ch);
543	                            }
544	                            col_ptr += in_tensor_ch;
545	                        }
546	                    }
547	                    FLUSH_IM2COL_UNROLL8();
548	                }
549	            }
550	
551	            /* === Middle region: no y-padding, split x into left/mid/right === */
552	            for (; cur_out_y < bound_y_end; cur_out_y++)
553	            {
554	                const long ker_y_start = cur_out_y * stride_y - pad_y;
555	
556	                /* -- Left part: needs x-padding -- */
557	                for (cur_out_x = 0; cur_out_x < bound_x_begin; cur_out_x++)
558	                {
559	                    const long ker_x_start = cur_out_x * stride_x - pad_x;
560	                    for (cur_ker_y = ker_y_start; cur_ker_y < ker_y_start + ker_dim_y; cur_ker_y++)
561	                    {
562	                        for (cur_ker_x = ker_x_start; cur_ker_x < ker_x_start + ker_dim_x; cur_ker_x++)
563	                        {
564	                            if (cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
565	                            {
566	                                nn_set_val_s8(col_ptr, pad_val, in_tensor_ch);
567	                            }
568	                            else
569	                            {
570	                                nn_dup_s8_m1(in_tensor + (cur_ker_y * in_tensor_dim_x + cur_ker_x) * in_tensor_ch, col_ptr, in_tensor_ch);
571	                            }
572	                            col_ptr += in_tensor_ch;
573	                        }
574	                    }
575	                    FLUSH_IM2COL_UNROLL8();
576	                }
577	
578	                /* -- Mid part: no padding at all, use bulk row copies -- */
579	                for (; cur_out_x < bound_x_end; cur_out_x++)
580	                {
581	                    const long ker_x_start = cur_out_x * stride_x - pad_x;
582	                    for (cur_ker_y = ker_y_start; cur_ker_y < ker_y_start + ker_dim_y; cur_ker_y++)
583	                    {
584	                        nn_dup_s8_m4(in_tensor + (cur_ker_y * in_tensor_dim_x + ker_x_start) * in_tensor_ch,
585	                                     col_ptr, in_tensor_ch * ker_dim_x);
586	                        col_ptr += in_tensor_ch * ker_dim_x;
587	                    }
588	                    FLUSH_IM2COL_UNROLL8();
589	                }
590	
591	                /* -- Right part: needs x-padding -- */
592	                for (; cur_out_x < out_tensor_dim_x; cur_out_x++)
593	                {
594	                    const long ker_x_start = cur_out_x * stride_x - pad_x;
595	                    for (cur_ker_y = ker_y_start; cur_ker_y < ker_y_start + ker_dim_y; cur_ker_y++)
596	                    {
597	                        for (cur_ker_x = ker_x_start; cur_ker_x < ker_x_start + ker_dim_x; cur_ker_x++)
598	                        {
599	                            if (cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
600	                            {
601	                                nn_set_val_s8(col_ptr, pad_val, in_tensor_ch);
602	                            }
603	                            else
604	                            {
605	                                nn_dup_s8_m1(in_tensor + (cur_ker_y * in_tensor_dim_x + cur_ker_x) * in_tensor_ch, col_ptr, in_tensor_ch);
606	                            }
607	                            col_ptr += in_tensor_ch;
608	                        }
609	                    }
610	                    FLUSH_IM2COL_UNROLL8();
611	                }
612	            }
613	
614	            /* === Bottom region: output rows that need y-padding === */
615	            for (; cur_out_y < out_tensor_dim_y; cur_out_y++)
616	            {
617	                for (cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
618	                {
619	                    const long ker_y_start = cur_out_y * stride_y - pad_y;
620	                    const long ker_x_start = cur_out_x * stride_x - pad_x;
621	                    for (cur_ker_y = ker_y_start; cur_ker_y < ker_y_start + ker_dim_y; cur_ker_y++)
622	                    {
623	                        for (cur_ker_x = ker_x_start; cur_ker_x < ker_x_start + ker_dim_x; cur_ker_x++)
624	                        {
625	                            if (cur_ker_y < 0 || cur_ker_y >= in_tensor_dim_y || cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
626	                            {
627	                                nn_set_val_s8(col_ptr, pad_val, in_tensor_ch);
628	                            }
629	                            else
630	                            {
631	                                nn_dup_s8_m1(in_tensor + (cur_ker_y * in_tensor_dim_x + cur_ker_x) * in_tensor_ch, col_ptr, in_tensor_ch);
632	                            }
633	                            col_ptr += in_tensor_ch;
634	                        }
635	                    }
636	                    FLUSH_IM2COL_UNROLL8();
637	                }
638	            }
639	
640	#undef FLUSH_IM2COL_UNROLL8
641	
642	            /* Handle left-over pixels (1..7 remaining) */
643	            if (col_ptr != eight_column_buf)
644	            {
645	                long leftover_bytes = col_ptr - eight_column_buf;
646	                int8_t *drain_ptr = eight_column_buf;
647	
648	                /* Drain 4 pixels if we have 4..7 left over */
649	                if (leftover_bytes >= 4 * col)
650	                {
651	                    out = nn_mat_mult_kernel_s8_offset_unroll4(ker_weight,
652	                                                          drain_ptr,
653	                                                          out_tensor_ch,
654	                                                          out_shift,
655	                                                          out_scale,
656	                                                          in_offset,
657	                                                          out_offset,
658	                                                          act_min,
659	                                                          act_max,
660	                                                          col,
661	                                                          contri_buf,
662	                                                          out);
663	                    drain_ptr += 4 * col;
664	                    leftover_bytes -= 4 * col;
665	                }
666	
667	                /* Drain 2 pixels if we have 2 or 3 left over */
668	                if (leftover_bytes >= 2 * col)
669	                {
670	                    out = nn_mat_mult_kernel_s8_offset_v4(ker_weight,
671	                                                          drain_ptr,
672	                                                          out_tensor_ch,
673	                                                          out_shift,
674	                                                          out_scale,
675	                                                          in_offset,
676	                                                          out_offset,
677	                                                          act_min,
678	                                                          act_max,
679	                                                          col,
680	                                                          contri_buf,
681	                                                          out);
682	                    drain_ptr += 2 * col;
683	                    leftover_bytes -= 2 * col;
684	                }
685	
686	                /* Handle 1 remaining pixel with scalar path */
687	                if (leftover_bytes > 0)
688	                {
689	                    uint32_t vl;
690	                    const int8_t *pWt = ker_weight;
691	                    const int32_t *pOut_scale = out_scale;
692	                    const int32_t *pOut_shift = out_shift;
693	                    int32_t *pContri_buf2 = contri_buf;
694	                    const int8_t *pIn_base = drain_ptr;
695	
696	                    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
697	                    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
698	
699	                    for (long i = 0; i < out_tensor_ch; i++)
700	                    {
701	                        uint32_t rhs_cols2 = col;
702	                        const int8_t *pIn = pIn_base;
703	
704	                        NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
705	                        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
706	
707	                        while (rhs_cols2 >= maxvl_per_loop)
708	                        {
709	                            NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
710	                            NDS_VEC_VLE8_V(NDS_VEC_V8, pIn);
711	                            NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
712	                            rhs_cols2 -= vl;
713	                            pIn += vl;
714	                            pWt += vl;
715	
716	                            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
717	                            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
718	                        }
