105	void static inline nn_dup_s8(const q7_t * src, q7_t * dst, uint32_t size)
106	{
107	#if defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
108	    long vl;
109	    long size2 = size;
110	    while(size2 > 0)
111	    {
112	        vl = __riscv_vsetvl_e8m8(size2);
113	        vint8m8_t vSrc = __riscv_vle8_v_i8m8(src, vl);
114	        __riscv_vse8(dst, vSrc, vl);
115	        src += vl;
116	        dst += vl;
117	        size2 -= vl;
118	    }
119	#elif defined(ENA_VEC_ISA)
120	    while(size > 0)
121	    {
122	        long vl;
123	        NDS_VEC_VSETVLI(vl, size, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
124	        NDS_VEC_VLE8_V(NDS_VEC_V0, src);
125	        src += vl;
126	        size -= vl;
127	        NDS_VEC_VSE8_V(NDS_VEC_V0, dst);
128	        dst += vl;
129	    }
130	#else
131	    memcpy(dst, src, size);
132	#endif
133	}
